class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int operations = 0;
        for (int i = k; i < arr.size(); i++) {
            if (arr[i - k] > arr[i]) {
                operations++;
                arr[i] = arr[i - k] + 1;
            }
        }
        return operations;
    }
};
